def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0
            continue
        ratio = item / capacity
        if item == 0:
            priorities[i] = 0
            continue
        base_score = 0
        if ratio < 0:
            priorities[i] = np.inf
            continue
        elif ratio == 0:
            priorities[i] = 0
            continue
        elif ratio <= 1:
            for n in range(1, 7):
                if n % 2 == 0:
                    base_score -= (ratio ** n) / (n + 1)
                else:
                    base_score += (ratio ** n) / n
            if ratio < 0.25:
                base_score *= 20
            elif ratio < 0.5:
                base_score *= 12
            elif ratio < 0.75:
                base_score *= 8
            else:
                base_score *= 5
            if 0.85 <= ratio <= 1:
                bonus = 0
                for p in range(1, 5):
                    if p % 3 == 0:
                        bonus += (ratio ** p) / (p * 2)
                    else:
                        bonus += (ratio ** p) / (p + 1)
                base_score += bonus
            priorities[i] = abs(base_score)
        else:
            penalty = 0
            for q in range(1, 5):
                penalty += (ratio ** (2 * q)) / (q * 3)
            comp_factor = sum([(np.sin(ratio * s) / (s + 1)) for s in range(1, 4)])
            priorities[i] = (ratio ** 4) + penalty + abs(comp_factor)
        if item > capacity and i % 2 == 0:
            priorities[i] *= 1.5
        elif capacity - item < 0.1 * capacity:
            priorities[i] *= 0.8
        else:
            for _ in range(3):
                priorities[i] = np.sqrt(priorities[i] + 1) * np.log1p(priorities[i] + 1)
    return priorities
